div.p:
c
first_space = memchr(line, ' ', line_len);
// line_len = 26, scans bytes 0..25
// Returns pointer to index 3 (the space after 'T')

c
path_start  = first_space + 1;  // index 4  → '/'
remaining   = line_len − (path_start − line);
//          = 26 − (4 − 0) = 22
second_space = memchr(path_start, ' ', 22);
// Scans bytes 4..25
// Returns pointer to index 18 (space before 'H')

c
if (path_len == 0)            return -1;   // empty path
if (path_len >= MAX_PATH_LEN) return -2;   // 414 URI Too Long
//  path_len = 15
//  MAX_PATH_LEN = 8192
//  15 < 8192  ✅  PASS

c
version_start = second_space + 1;        // index 19 → 'H'
version_len   = line_len − (version_start − line);
//            = 26 − (19 − 0) = 7
// Bytes 19..25 = "HTTP/1.1"
if (version_len > 0 && version_start[version_len-1] == '\r')
version_len--;   // strip \r if present

c
memcpy(req->version, version_start, 8);
req->version[8] = '\0';
// req->version = "HTTP/1.1"
return 0;   // HTTP_PARSE_OK

c
first_space = memchr(line, ' ', line_len);
if (!first_space) return -1;   // → 400 Bad Request

c
second_space = memchr(path_start, ' ', remaining);
if (!second_space) return -1;  // → 400 Bad Request

c
if (path_len >= MAX_PATH_LEN) return -2;
// caller maps -2 → 414 URI Too Long

c
if (method_len == 0)   return -1;

if (version_len == 0)  return -1;

if (method_len  >= MAX_METHOD_LEN)  return -1;
if (version_len >= MAX_VERSION_LEN) return -1;
